"use strict";(globalThis.webpackChunkmy_own_blog=globalThis.webpackChunkmy_own_blog||[]).push([[847],{44159(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>h,frontMatter:()=>s,metadata:()=>i,toc:()=>c});const i=JSON.parse('{"id":"snp-atk-def/index","title":"Reflections on the competition","description":"At the end of January, I took part in an internal Information Security drill at my company.","source":"@site/docs/snp-atk-def/index.mdx","sourceDirName":"snp-atk-def","slug":"/snp-atk-def/","permalink":"/docs/snp-atk-def/","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"sidebar_position":1},"sidebar":"writeupsSidebar","previous":{"title":"SNP ATK & DEF","permalink":"/docs/category/snp-atk--def"},"next":{"title":"Level 1","permalink":"/docs/snp-atk-def/level-1/"}}');var o=n(74848),a=n(28453);const s={sidebar_position:1},r="Reflections on the competition",l={},c=[];function d(e){const t={a:"a",blockquote:"blockquote",br:"br",h1:"h1",header:"header",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.header,{children:(0,o.jsx)(t.h1,{id:"reflections-on-the-competition",children:"Reflections on the competition"})}),"\n",(0,o.jsx)(t.p,{children:'At the end of January, I took part in an internal Information Security drill at my company.\r\nThe competition followed an "attack - defense" style format:\r\neach team was responsible for defending its own website while simultaneously attacking the systems of other teams.'}),"\n",(0,o.jsx)(t.p,{children:"Each team was supposed to have five members, and the exercise ran continuously for around eight hours.\r\nDue to a few constraints, my team ended up competing with only four people.\r\nEven so, we managed to perform extremely well and ultimately secured first place, which was both surprising and rewarding."}),"\n",(0,o.jsx)(t.p,{children:"On the defensive side, every team had to build its own Web Application Firewall (WAF).\r\nThe goal was to design effective whitelist and blacklist rules that could block malicious attacks without disrupting legitimate user behavior.\r\nStriking this balance turned out to be more challenging than it initially sounded."}),"\n",(0,o.jsx)(t.p,{children:"On the offensive side, teams were tasked with exploiting five vulnerabilities across 30 rounds, each round requiring us to capture a flag.\r\nWe were also provided with the source code for each level.\r\nBecause of this, the attacking teams needed to move quickly and proactively - analyze the code fast, identify the right payloads, and exploit the vulnerabilities before the WAF rules could adapt and block them."}),"\n",(0,o.jsxs)(t.p,{children:["Although the source code was available, in this write-up I will approach the first two levels using a black-box perspective, focusing on how an attacker might discover and exploit the vulnerabilities without relying directly on the source code.",(0,o.jsx)(t.br,{}),"\n","For the remaining three levels, I will switch to a white-box approach, analyzing the vulnerabilities based on the provided source code."]}),"\n",(0,o.jsx)(t.p,{children:"If you are interested in exploring the first two levels from a white-box perspective as well, feel free to leave your feedback or suggestions - I may consider adding that analysis later."}),"\n",(0,o.jsxs)(t.p,{children:["For this series, the focus will mainly be on the attacker's perspective and the exploitation process.",(0,o.jsx)(t.br,{}),"\n","As for the defensive side, I plan to cover it separately in the ",(0,o.jsx)(t.a,{href:"https://blog.solivaquaant.site/labs/intro",children:(0,o.jsx)(t.strong,{children:"Labs section"})}),".",(0,o.jsx)(t.br,{}),"\n","There, I will walk through how to build a simple WAF using ModSecurity, as well as how to write and customize your own rules.\r\nStay tuned for that content."]}),"\n",(0,o.jsx)(t.p,{children:"For these write-ups, I recreated the web applications locally using Docker, while modifying sensitive company-related information and flag values in accordance with the organizers' requirements."}),"\n",(0,o.jsx)(t.p,{children:"Before the competition began, my assigned role was to manage the WAF and design appropriate whitelist and blacklist rules.\r\nHowever, once the competition was underway, I realized that relying on a single pentester could significantly slow down the vulnerability discovery process.\r\nAs a result, I shifted my focus to supporting the pentester directly and contributed to finding and exploiting several vulnerabilities myself."}),"\n",(0,o.jsx)(t.p,{children:"Most importantly, I would like to give a special shout-out to the other three members of my team.\r\nThank you to P, our team leader, for building such a strong and well-balanced team;\r\nto A, for constantly pushing and motivating me to research and prepare ahead of the competition;\r\nand to N, for sharing great ideas and useful tools that made log analysis much easier."}),"\n",(0,o.jsx)(t.p,{children:"Although there were still a few moments I wish had gone better, overall this competition was a genuinely valuable and enjoyable experience."}),"\n",(0,o.jsx)(t.p,{children:"And now, let's take a look at the write-ups I've put together."}),"\n",(0,o.jsxs)(t.blockquote,{children:["\n",(0,o.jsx)(t.p,{children:"If you have any feedback, questions, or suggestions, please don't hesitate to reach out and discuss them with me ^^"}),"\n"]})]})}function h(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},28453(e,t,n){n.d(t,{R:()=>s,x:()=>r});var i=n(96540);const o={},a=i.createContext(o);function s(e){const t=i.useContext(a);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:s(e.components),i.createElement(a.Provider,{value:t},e.children)}}}]);